class Solution:
    def smallestString(self, s):
        n = len(s)
        best = None
        for i in range(n):
            for j in range(i, n):
                chars = list(s)
                for k in range(i, j + 1):
                    chars[k] = 'z' if chars[k] == 'a' else chr(ord(chars[k]) - 1)
                cand = ''.join(chars)
                if best is None or cand < best:
                    best = cand
        return best

