class Solution:
    def smallestString(self, s: str) -> str:
        n = len(s)
        chars = list(s)
        i = 0
        while i < n and chars[i] == 'a':
            i += 1
        if i == n:
            chars[-1] = 'z'
            return ''.join(chars)
        j = i
        while j < n and chars[j] != 'a':
            chars[j] = chr(ord(chars[j]) - 1)
            j += 1
        return ''.join(chars)

