var smallestString = function(s) {
    const n = s.length;
    const chars = s.split('');
    let i = 0;
    while (i < n && chars[i] === 'a') i++;
    if (i === n) {
        chars[n - 1] = 'z';
        return chars.join('');
    }
    let j = i;
    while (j < n && chars[j] !== 'a') {
        chars[j] = String.fromCharCode(chars[j].charCodeAt(0) - 1);
        j++;
    }
    return chars.join('');
};
